import React from "react";
import {
  AbsoluteFill,
  Img,
  useCurrentFrame,
  useVideoConfig,
  Composition,
} from "remotion";
import { z } from "zod";

// 1. Définition du schéma Zod pour la validation et l'interface du Studio Remotion
export const PortraitSchema = z.object({
  imageUrl: z.string(),
  flowers: z.array(z.string()).min(1),
  flowerSize: z.number(),
  nFlower: z.number().min(1),
});

// 2. Extraction automatique du type TypeScript à partir du schéma Zod
export type PortraitProps = z.infer<typeof PortraitSchema>;

// 3. Le composant principal qui gère l'affichage et l'animation
export const RotatingFlowers: React.FC<PortraitProps> = ({
  imageUrl,
  flowers,
  flowerSize,
  nFlower,
}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // --- Paramètres de l'animation ---
  const radius = 225; // Rayon de l'orbite
  const rotationSpeed = 0.2; // Vitesse de rotation (tours par seconde)

  // Calcul de la rotation globale en degrés
  const globalRotation = (frame / fps) * 360 * rotationSpeed;

  // --- Animations (Spring) ---
  // // Animation de "pop" pour l'image centrale
  // const imageScale = spring({
  //   fps,
  //   frame,
  //   config: {
  //     mass: 1,
  //     damping: 14,
  //     stiffness: 120,
  //   },
  // });

  // // Animation de "pop" pour les fleurs (avec un léger délai de 10 frames)
  // const flowerScale = spring({
  //   fps,
  //   frame: frame - 10,
  //   config: {
  //     mass: 0.8,
  //     damping: 12,
  //     stiffness: 100,
  //   },
  // });

  return (
    <AbsoluteFill
      style={{
        background: 'linear-gradient(135deg, #a18cd1 0%, #fbc2eb 100%)',
        justifyContent: "center",
        alignItems: "center",
      }}
    >
      {/* Image Centrale (Photo) */}
      <Img
        src={imageUrl}
        style={{
          width: "400px",
          height: "400px",
          borderRadius: "50%",
          objectFit: "cover",
          // transform: `scale(${imageScale})`,
          boxShadow: "0 20px 50px rgba(0,0,0,0.25)",
          border: "10px solid white",
          // zIndex: 10, // S'assure que la photo est au-dessus des fleurs
        }}
      />

      {/* Conteneur invisible pour la rotation des fleurs */}
      <div
        style={{
          position: "absolute",
          width: 0,
          height: 0,
          transform: `rotate(${globalRotation}deg)`,
        }}
      >
        {Array.from({ length: nFlower }).map((_, i) => {
          // Répartition uniforme des emojis sur 360 degrés
          const angle = (i / nFlower) * 360;

          return (
            <div
              key={i}
              style={{
                position: "absolute",
                // Logique de transformation :
                // 1. On tourne selon l'angle de la fleur
                // 2. On l'éloigne du centre (translateY)
                // 3. On annule la rotation globale et locale pour que l'emoji reste toujours droit
                transform: `rotate(${angle}deg) translateY(-${radius}px) rotate(-${angle + globalRotation}deg)`, // scale(${flowerScale})`,
                fontSize: `${flowerSize}px`,
                left: `${-flowerSize / 2}px`, // Centrage horizontal (moitié de la taille de la police)
                top: `${-flowerSize / 2}px`, // Centrage vertical
                textShadow: "0 4px 15px rgba(0,0,0,0.1)",
              }}
            >
              {flowers[i % flowers.length]}
            </div>
          );
        })}
      </div>
    </AbsoluteFill>
  );
};

// 4. La racine Remotion qui déclare la Composition avec le schéma
export const RemotionRoot: React.FC = () => {
  return (
    <>
      <Composition
        id="PortraitFleuri"
        component={RotatingFlowers}
        durationInFrames={150} // 10 secondes à 30fps
        fps={30}
        width={600}
        height={600}
        schema={PortraitSchema} // <--- AJOUT DU SCHÉMA ZOD ICI
        defaultProps={{
          imageUrl:
            "data:image/jpg;base64,",
          flowers: ["🌹", "🌷", "🌻", "🌼", "🌸"],
          flowerSize: 80,
          nFlower: 10,
        }}
      />
    </>
  );
};
